(window.webpackJsonp=window.webpackJsonp||[]).push([[760],{751:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[][]}</span> <span class=\\"hljs-variable\\">grid</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> minCost = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">grid</span>) </span>{\\n  <span class=\\"hljs-keyword\\">let</span> m=grid.length\\n  <span class=\\"hljs-keyword\\">let</span> n=grid[<span class=\\"hljs-number\\">0</span>].length\\n  <span class=\\"hljs-keyword\\">if</span>(n===<span class=\\"hljs-number\\">1</span> &amp;&amp; m===<span class=\\"hljs-number\\">1</span>)<span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-number\\">0</span>\\n  <span class=\\"hljs-keyword\\">let</span> arr=[]\\n  <span class=\\"hljs-keyword\\">let</span> moves=[[<span class=\\"hljs-number\\">0</span>,<span class=\\"hljs-number\\">1</span>],[<span class=\\"hljs-number\\">0</span>,<span class=\\"hljs-number\\">-1</span>],[<span class=\\"hljs-number\\">1</span>,<span class=\\"hljs-number\\">0</span>],[<span class=\\"hljs-number\\">-1</span>,<span class=\\"hljs-number\\">0</span>]]\\n  <span class=\\"hljs-keyword\\">let</span> hash={}\\n  arr.push([<span class=\\"hljs-number\\">0</span>,<span class=\\"hljs-number\\">0</span>,grid[<span class=\\"hljs-number\\">0</span>][<span class=\\"hljs-number\\">0</span>],<span class=\\"hljs-number\\">0</span>])\\n  <span class=\\"hljs-keyword\\">let</span> step=<span class=\\"hljs-number\\">0</span>\\n  <span class=\\"hljs-keyword\\">let</span> minStep=<span class=\\"hljs-literal\\">Infinity</span>\\n  <span class=\\"hljs-keyword\\">while</span>(arr.length&gt;<span class=\\"hljs-number\\">0</span>){\\n    <span class=\\"hljs-keyword\\">let</span> len=arr.length\\n    <span class=\\"hljs-comment\\">// console.log(arr,noModifyDone,modifyDone)</span>\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;len;i++){\\n      <span class=\\"hljs-keyword\\">let</span> [x,y,idx,step]=arr.shift()\\n      <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> j=<span class=\\"hljs-number\\">0</span>;j&lt;moves.length;j++){\\n        <span class=\\"hljs-keyword\\">if</span>(j===idx<span class=\\"hljs-number\\">-1</span>)<span class=\\"hljs-keyword\\">continue</span>\\n        <span class=\\"hljs-keyword\\">let</span> [dx,dy]=moves[j]\\n        <span class=\\"hljs-keyword\\">let</span> nx=dx+x\\n        <span class=\\"hljs-keyword\\">let</span> ny=dy+y\\n        <span class=\\"hljs-keyword\\">if</span>(nx&lt;<span class=\\"hljs-number\\">0</span> || nx&gt;=m || ny&lt;<span class=\\"hljs-number\\">0</span> || ny&gt;=n)<span class=\\"hljs-keyword\\">continue</span>\\n        <span class=\\"hljs-keyword\\">if</span>(hash[nx+<span class=\\"hljs-string\\">\' \'</span>+ny]!=<span class=\\"hljs-literal\\">null</span> &amp;&amp; hash[nx+<span class=\\"hljs-string\\">\' \'</span>+ny]&lt;=step+<span class=\\"hljs-number\\">1</span>)<span class=\\"hljs-keyword\\">continue</span>\\n        <span class=\\"hljs-keyword\\">if</span>(nx===m<span class=\\"hljs-number\\">-1</span> &amp;&amp; ny===n<span class=\\"hljs-number\\">-1</span>){\\n          minStep=<span class=\\"hljs-built_in\\">Math</span>.min(minStep,step+<span class=\\"hljs-number\\">1</span>)\\n        }\\n        hash[nx+<span class=\\"hljs-string\\">\' \'</span>+ny]=step+<span class=\\"hljs-number\\">1</span>\\n        <span class=\\"hljs-keyword\\">if</span>(step+<span class=\\"hljs-number\\">1</span>&lt;minStep)arr.push([nx,ny,grid[nx][ny],step+<span class=\\"hljs-number\\">1</span>])\\n      }        \\n      <span class=\\"hljs-keyword\\">let</span> [dx,dy]=moves[idx<span class=\\"hljs-number\\">-1</span>]\\n      <span class=\\"hljs-keyword\\">let</span> nx=dx+x\\n      <span class=\\"hljs-keyword\\">let</span> ny=dy+y\\n      <span class=\\"hljs-keyword\\">if</span>(nx&lt;<span class=\\"hljs-number\\">0</span> || nx&gt;=m || ny&lt;<span class=\\"hljs-number\\">0</span> || ny&gt;=n)<span class=\\"hljs-keyword\\">continue</span>\\n      <span class=\\"hljs-keyword\\">if</span>(hash[nx+<span class=\\"hljs-string\\">\' \'</span>+ny]!=<span class=\\"hljs-literal\\">null</span> &amp;&amp; hash[nx+<span class=\\"hljs-string\\">\' \'</span>+ny]&lt;=step)<span class=\\"hljs-keyword\\">continue</span>\\n      hash[nx+<span class=\\"hljs-string\\">\' \'</span>+ny]=step\\n      <span class=\\"hljs-keyword\\">if</span>(nx===m<span class=\\"hljs-number\\">-1</span> &amp;&amp; ny===n<span class=\\"hljs-number\\">-1</span>){\\n        minStep=<span class=\\"hljs-built_in\\">Math</span>.min(minStep,step)\\n      }\\n      <span class=\\"hljs-keyword\\">if</span>(step&lt;minStep)arr.push([nx,ny,grid[nx][ny],step])\\n    }\\n  }\\n  <span class=\\"hljs-keyword\\">return</span> minStep\\n};\\n</code></pre>\\n"],"titleSlug":"minimum-cost-to-make-at-least-one-valid-path-in-a-grid","hasThinking":false,"content":"<p>\u7ed9\u4f60\u4e00\u4e2a m x n \u7684\u7f51\u683c\u56fe&nbsp;<code>grid</code>&nbsp;\u3002&nbsp;<code>grid</code>&nbsp;\u4e2d\u6bcf\u4e2a\u683c\u5b50\u90fd\u6709\u4e00\u4e2a\u6570\u5b57\uff0c\u5bf9\u5e94\u7740\u4ece\u8be5\u683c\u5b50\u51fa\u53d1\u4e0b\u4e00\u6b65\u8d70\u7684\u65b9\u5411\u3002&nbsp;<code>grid[i][j]</code>&nbsp;\u4e2d\u7684\u6570\u5b57\u53ef\u80fd\u4e3a\u4ee5\u4e0b\u51e0\u79cd\u60c5\u51b5\uff1a</p>\\n\\n<ul>\\n\\t<li><strong>1</strong>&nbsp;\uff0c\u4e0b\u4e00\u6b65\u5f80\u53f3\u8d70\uff0c\u4e5f\u5c31\u662f\u4f60\u4f1a\u4ece <code>grid[i][j]</code>&nbsp;\u8d70\u5230 <code>grid[i][j + 1]</code></li>\\n\\t<li><strong>2</strong>&nbsp;\uff0c\u4e0b\u4e00\u6b65\u5f80\u5de6\u8d70\uff0c\u4e5f\u5c31\u662f\u4f60\u4f1a\u4ece <code>grid[i][j]</code>&nbsp;\u8d70\u5230 <code>grid[i][j - 1]</code></li>\\n\\t<li><strong>3</strong>&nbsp;\uff0c\u4e0b\u4e00\u6b65\u5f80\u4e0b\u8d70\uff0c\u4e5f\u5c31\u662f\u4f60\u4f1a\u4ece <code>grid[i][j]</code>&nbsp;\u8d70\u5230 <code>grid[i + 1][j]</code></li>\\n\\t<li><strong>4</strong>&nbsp;\uff0c\u4e0b\u4e00\u6b65\u5f80\u4e0a\u8d70\uff0c\u4e5f\u5c31\u662f\u4f60\u4f1a\u4ece <code>grid[i][j]</code>&nbsp;\u8d70\u5230 <code>grid[i - 1][j]</code></li>\\n</ul>\\n\\n<p>\u6ce8\u610f\u7f51\u683c\u56fe\u4e2d\u53ef\u80fd\u4f1a\u6709&nbsp;<strong>\u65e0\u6548\u6570\u5b57</strong>&nbsp;\uff0c\u56e0\u4e3a\u5b83\u4eec\u53ef\u80fd\u6307\u5411&nbsp;<code>grid</code>&nbsp;\u4ee5\u5916\u7684\u533a\u57df\u3002</p>\\n\\n<p>\u4e00\u5f00\u59cb\uff0c\u4f60\u4f1a\u4ece\u6700\u5de6\u4e0a\u89d2\u7684\u683c\u5b50&nbsp;<code>(0,0)</code>&nbsp;\u51fa\u53d1\u3002\u6211\u4eec\u5b9a\u4e49\u4e00\u6761&nbsp;<strong>\u6709\u6548\u8def\u5f84</strong>&nbsp;\u4e3a\u4ece\u683c\u5b50&nbsp;<code>(0,0)</code>&nbsp;\u51fa\u53d1\uff0c\u6bcf\u4e00\u6b65\u90fd\u987a\u7740\u6570\u5b57\u5bf9\u5e94\u65b9\u5411\u8d70\uff0c\u6700\u7ec8\u5728\u6700\u53f3\u4e0b\u89d2\u7684\u683c\u5b50&nbsp;<code>(m - 1, n - 1)</code>&nbsp;\u7ed3\u675f\u7684\u8def\u5f84\u3002\u6709\u6548\u8def\u5f84&nbsp;<strong>\u4e0d\u9700\u8981\u662f\u6700\u77ed\u8def\u5f84</strong>&nbsp;\u3002</p>\\n\\n<p>\u4f60\u53ef\u4ee5\u82b1\u8d39&nbsp;<code>cost = 1</code>&nbsp;\u7684\u4ee3\u4ef7\u4fee\u6539\u4e00\u4e2a\u683c\u5b50\u4e2d\u7684\u6570\u5b57\uff0c\u4f46\u6bcf\u4e2a\u683c\u5b50\u4e2d\u7684\u6570\u5b57&nbsp;<strong>\u53ea\u80fd\u4fee\u6539\u4e00\u6b21</strong>&nbsp;\u3002</p>\\n\\n<p>\u8bf7\u4f60\u8fd4\u56de\u8ba9\u7f51\u683c\u56fe\u81f3\u5c11\u6709\u4e00\u6761\u6709\u6548\u8def\u5f84\u7684\u6700\u5c0f\u4ee3\u4ef7\u3002</p>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<p><img alt=\\"\\" src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/uploads/2020/02/29/grid1.png\\" style=\\"height: 528px; width: 542px;\\"></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>grid = [[1,1,1,1],[2,2,2,2],[1,1,1,1],[2,2,2,2]]\\n<strong>\u8f93\u51fa\uff1a</strong>3\\n<strong>\u89e3\u91ca\uff1a</strong>\u4f60\u5c06\u4ece\u70b9 (0, 0) \u51fa\u53d1\u3002\\n\u5230\u8fbe (3, 3) \u7684\u8def\u5f84\u4e3a\uff1a (0, 0) --&gt; (0, 1) --&gt; (0, 2) --&gt; (0, 3) \u82b1\u8d39\u4ee3\u4ef7 cost = 1 \u4f7f\u65b9\u5411\u5411\u4e0b --&gt; (1, 3) --&gt; (1, 2) --&gt; (1, 1) --&gt; (1, 0) \u82b1\u8d39\u4ee3\u4ef7 cost = 1 \u4f7f\u65b9\u5411\u5411\u4e0b --&gt; (2, 0) --&gt; (2, 1) --&gt; (2, 2) --&gt; (2, 3) \u82b1\u8d39\u4ee3\u4ef7 cost = 1 \u4f7f\u65b9\u5411\u5411\u4e0b --&gt; (3, 3)\\n\u603b\u82b1\u8d39\u4e3a cost = 3.\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<p><img alt=\\"\\" src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/uploads/2020/02/29/grid2.png\\" style=\\"height: 408px; width: 419px;\\"></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>grid = [[1,1,3],[3,2,2],[1,1,4]]\\n<strong>\u8f93\u51fa\uff1a</strong>0\\n<strong>\u89e3\u91ca\uff1a</strong>\u4e0d\u4fee\u6539\u4efb\u4f55\u6570\u5b57\u4f60\u5c31\u53ef\u4ee5\u4ece (0, 0) \u5230\u8fbe (2, 2) \u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<p><img alt=\\"\\" src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/uploads/2020/02/29/grid3.png\\" style=\\"height: 302px; width: 314px;\\"></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>grid = [[1,2],[4,3]]\\n<strong>\u8f93\u51fa\uff1a</strong>1\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 4\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>grid = [[2,2,2],[2,2,2]]\\n<strong>\u8f93\u51fa\uff1a</strong>3\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 5\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>grid = [[4]]\\n<strong>\u8f93\u51fa\uff1a</strong>0\\n</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>m == grid.length</code></li>\\n\\t<li><code>n == grid[i].length</code></li>\\n\\t<li><code>1 &lt;= m, n &lt;= 100</code></li>\\n</ul>\\n","title":"1368. \u4f7f\u7f51\u683c\u56fe\u81f3\u5c11\u6709\u4e00\u6761\u6709\u6548\u8def\u5f84\u7684\u6700\u5c0f\u4ee3\u4ef7","relatedTags":["\u5e7f\u5ea6\u4f18\u5148\u641c\u7d22"],"difficult":"Hard","lang":["javascript"],"uniqueID":"1368"}')}}]);